import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as a,o as r,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"快速入门","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/quickstart.md","filePath":"zh/getting-started/quickstart.md"}'),i={name:"zh/getting-started/quickstart.md"};function c(l,t,n,d,p,g){return r(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="快速入门" tabindex="-1"><i class="ph ph-target"></i> 快速入门 <a class="header-anchor" href="#快速入门" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; 快速入门&quot;">​</a></h1><p>WebAP 插件采用 <em>即插即用 (Plug-and-Play)</em> 方法设计。无需编写代码或将管理器添加到启动场景——系统会自动初始化。</p><h2 id="_1-启用插件" tabindex="-1">1. 启用插件 <a class="header-anchor" href="#_1-启用插件" aria-label="Permalink to &quot;1. 启用插件&quot;">​</a></h2><ol><li>导航至 <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong>。</li><li>切换 <strong>Enable Web Adaptive Performance</strong>。</li><li>展开 Scalers 选项卡并启用最适合您游戏细节的附加模块（例如，物理步长或阴影质量）（有关详细信息，请参阅 <a href="./../scalers/reference">缩放器参考</a>）。</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">默认设置</p><p>默认设置经过预配置，可为大多数项目提供最佳性能。请保持它们不变。</p></div><h2 id="_2-配置播放器设置" tabindex="-1">2. 配置播放器设置 <a class="header-anchor" href="#_2-配置播放器设置" aria-label="Permalink to &quot;2. 配置播放器设置&quot;">​</a></h2><p>为了使插件的跟踪器 (Tracker) 能够在数学上区分处理器 (CPU) 延迟和显卡 (GPU) 延迟，它需要访问精确的硬件帧时序。</p><div class="warning custom-block"><p class="custom-block-title">帧时序统计 (Frame Timing Stats)</p><p>导航至 <strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> 并勾选 <strong>Frame Timing Stats</strong>。如果没有此设置，瓶颈 (Bottleneck) 检测将无法运行。</p></div><h2 id="_3-配置图形" tabindex="-1">3. 配置图形 <a class="header-anchor" href="#_3-配置图形" aria-label="Permalink to &quot;3. 配置图形&quot;">​</a></h2><p>停止为不同设备创建单独的质量预设（低、中、高），并强迫玩家手动选择它们。</p><div class="tip custom-block"><p class="custom-block-title">最大化图形质量</p><p>将您的项目配置为最大质量。对于 BiRP，在 <code>Project Settings -&gt; Quality</code> 中执行此操作，而对于 URP，在您的 <code>URP Asset</code> 内执行。如果玩家的设备缺乏性能余量 (Performance Headroom)，插件将自动平滑地缩小负载，仅利用您已启用的缩放器 (Scalers)。</p></div>',12)])])}const u=a(i,[["render",c]]);export{_ as __pageData,u as default};
